public final class com.example.layout.CustomRepoLayout extends org.machanism.machai.project.layout.ProjectLayout {
  @java.lang.Override
  public java.util.Collection<java.lang.String> getSources() {
    return java.util.Collections.singletonList("modules/core/src");
  }

  @java.lang.Override
  public java.util.Collection<java.lang.String> getDocuments() {
    return java.util.Collections.singletonList("docs");
  }

  @java.lang.Override
  public java.util.Collection<java.lang.String> getTests() {
    return java.util.Collections.singletonList("modules/core/test");
  }
}

