public final class com.example.tools.DetectLayoutApp {
  public static void main(java.lang.String[] args) throws java.lang.Exception {
    java.io.File repo = new java.io.File(args.length > 0 ? args[0] : ".");
    org.machanism.machai.project.layout.ProjectLayout layout = org.machanism.machai.project.ProjectLayoutManager.detectProjectLayout(repo);
    java.lang.System.out.println("Layout type: " + layout.getProjectLayoutType());
    java.lang.System.out.println("Sources: " + layout.getSources());
    java.lang.System.out.println("Tests: " + layout.getTests());
    java.lang.System.out.println("Docs: " + layout.getDocuments());
  }
}

public final class com.example.tools.ListProjectFilesApp {
  public static void main(java.lang.String[] args) {
    java.io.File root = new java.io.File(args.length > 0 ? args[0] : ".");
    java.util.List<java.io.File> files = org.machanism.machai.project.layout.ProjectLayout.findFiles(root);
    for (java.io.File file : files) {
      java.lang.System.out.println(file.getPath());
    }
  }
}

public final class com.example.tools.ModuleReporter extends org.machanism.machai.project.ProjectProcessor {
  @java.lang.Override
  public void processFolder(org.machanism.machai.project.layout.ProjectLayout processor) {
    java.lang.System.out.println("Project name: " + processor.getProjectName());
    java.lang.System.out.println("Project id: " + processor.getProjectId());
    java.lang.System.out.println("Layout type: " + processor.getProjectLayoutType());
    java.lang.System.out.println("Sources: " + processor.getSources());
  }

  public static void main(java.lang.String[] args) throws java.lang.Exception {
    new com.example.tools.ModuleReporter().scanFolder(new java.io.File(args.length > 0 ? args[0] : "."));
  }
}
